import React, { useState, useEffect } from 'react';
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate,
  Link,
  useNavigate,
  useLocation
} from 'react-router-dom';
import {
  ThemeProvider,
  createTheme,
  CssBaseline,
  AppBar,
  Toolbar,
  Typography,
  Button,
  Box,
  Card,
  CardContent,
  TextField,
  IconButton,
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  CircularProgress,
  Alert,
  Grid,
  LinearProgress,
  Chip,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Paper,
  Container,
  Avatar,
  Divider,
  CardActions,
  Tooltip,
  Stack,
  useMediaQuery,
  Fade,
  Grow,
  Zoom,
  Menu,
  MenuItem,
  ToggleButton,
  ToggleButtonGroup,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Select,
  FormControl,
  InputLabel,
  FormHelperText,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  Stepper,
  Step,
  StepLabel,
  StepContent
} from '@mui/material';
import { alpha } from '@mui/material/styles';
import {
  Menu as MenuIcon,
  Dashboard as DashboardIcon,
  Upload as UploadIcon,
  Assessment as AssessmentIcon,
  Work as WorkIcon,
  History as HistoryIcon,
  Logout as LogoutIcon,
  Analytics as AnalyticsIcon,
  CheckCircle as CheckCircleIcon,
  Error as ErrorIcon,
  TrendingUp as TrendingUpIcon,
  Description as DescriptionIcon,
  CloudUpload as CloudUploadIcon,
  Business as BusinessIcon,
  Rocket as RocketIcon,
  Security as SecurityIcon,
  Visibility as VisibilityIcon,
  Add as AddIcon,
  AutoAwesome as AutoAwesomeIcon,
  Psychology as PsychologyIcon,
  Calculate as CalculateIcon,
  ThumbUp as ThumbUpIcon,
  ThumbDown as ThumbDownIcon,
  Apps as AppsIcon,
  FormatListBulleted as FormatListBulletedIcon,
  Speed as SpeedIcon,
  InsertDriveFile as InsertDriveFileIcon,
  PictureAsPdf as PictureAsPdfIcon,
  Article as ArticleIcon,
  Search as SearchIcon,
  Warning as WarningIcon,
  Check as CheckIcon,
  ExpandMore as ExpandMoreIcon,
  Timeline as TimelineIcon,
  Lightbulb as LightbulbIcon,
  School as SchoolIcon,
  WorkHistory as WorkHistoryIcon,
  Celebration as CelebrationIcon
} from '@mui/icons-material';
import { DropzoneArea } from 'mui-file-dropzone';
import axios from 'axios';

// ==================== PINK THEME ====================

const theme = createTheme({
  palette: {
    mode: 'light',
    primary: { main: '#ff69b4', light: '#ff9acb', dark: '#ff1493' },
    secondary: { main: '#ff6b6b', light: '#ff8787', dark: '#fa5252' },
    success: { main: '#51cf66', light: '#69db7e', dark: '#37b24d' },
    warning: { main: '#ff922b', light: '#ffa94d', dark: '#f76707' },
    error: { main: '#ff6b6b', light: '#ff8787', dark: '#fa5252' },
    background: { default: '#fff5f8', paper: '#ffffff' },
  },
  typography: { fontFamily: '"Inter", "Poppins", "Roboto", sans-serif', h4: { fontWeight: 600 }, h5: { fontWeight: 600 } },
  shape: { borderRadius: 16 },
  components: {
    MuiButton: { styleOverrides: { root: { textTransform: 'none', fontWeight: 600, borderRadius: 12, padding: '8px 20px' } } },
    MuiCard: { styleOverrides: { root: { borderRadius: 20, boxShadow: '0px 4px 20px rgba(0, 0, 0, 0.05)', transition: 'all 0.3s ease' } } },
  },
});

// ==================== API SERVICE ====================

const API_BASE_URL = 'http://localhost:8000/api';

const api = axios.create({ baseURL: API_BASE_URL, headers: { 'Content-Type': 'application/json' } });

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('access_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

api.interceptors.response.use((response) => response, (error) => {
  if (error.response?.status === 401) localStorage.removeItem('access_token');
  return Promise.reject(error);
});

// ==================== AUTH CONTEXT ====================

const AuthContext = React.createContext(null);

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('access_token');
    if (token) {
      api.get('/auth/profile').then(res => setUser(res.data)).catch(() => localStorage.removeItem('access_token')).finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  const login = async (username, password) => {
    const formData = new FormData();
    formData.append('username', username);
    formData.append('password', password);
    const response = await axios.post(`${API_BASE_URL}/auth/login`, formData);
    localStorage.setItem('access_token', response.data.access_token);
    const profile = await api.get('/auth/profile');
    setUser(profile.data);
    return response.data;
  };

  const signup = async (userData) => {
    const response = await api.post('/auth/signup', userData);
    return response.data;
  };

  const logout = () => {
    localStorage.removeItem('access_token');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, signup, logout, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

// ==================== HOME PAGE ====================

const HomePage = () => {
  const navigate = useNavigate();
  const features = [
    { icon: <PsychologyIcon />, title: 'AI-Powered Analysis', description: 'Get intelligent insights', color: '#ff69b4' },
    { icon: <SpeedIcon />, title: 'Instant Results', description: 'Analyze in seconds', color: '#ff6b6b' },
    { icon: <CalculateIcon />, title: 'ATS Score', description: 'Know your compatibility', color: '#ff922b' },
    { icon: <WorkIcon />, title: 'Job Matching', description: 'Find perfect matches', color: '#ff69b4' },
  ];

  return (
    <Box>
      <Box sx={{ background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)', color: 'white', pt: 12, pb: 8 }}>
        <Container maxWidth="lg">
          <Grid container spacing={6} alignItems="center">
            <Grid item xs={12} md={6}>
              <Grow in timeout={1000}>
                <Box>
                  <Chip icon={<AutoAwesomeIcon />} label="AI-Powered Resume Analysis" sx={{ bgcolor: 'rgba(255,255,255,0.2)', color: 'white', mb: 3 }} />
                  <Typography variant="h3" gutterBottom sx={{ fontWeight: 800 }}>Land Your Dream Job with AI</Typography>
                  <Typography variant="h6" sx={{ mb: 4, opacity: 0.9 }}>Get past ATS systems with intelligent resume analysis and job matching</Typography>
                  <Stack direction="row" spacing={2}>
                    <Button variant="contained" size="large" onClick={() => navigate('/signup')} sx={{ bgcolor: 'white', color: '#ff69b4', px: 4 }} startIcon={<RocketIcon />}>Get Started Free</Button>
                    <Button variant="outlined" size="large" onClick={() => navigate('/login')} sx={{ borderColor: 'white', color: 'white' }}>Sign In</Button>
                  </Stack>
                </Box>
              </Grow>
            </Grid>
            <Grid item xs={12} md={6}>
              <Zoom in timeout={1000}>
                <Box sx={{ textAlign: 'center' }}>
                  <img src="https://cdn-icons-png.flaticon.com/512/1055/1055687.png" alt="Resume" style={{ width: '80%', maxWidth: 300 }} />
                </Box>
              </Zoom>
            </Grid>
          </Grid>
        </Container>
      </Box>
      <Container maxWidth="lg" sx={{ py: 6 }}>
        <Typography variant="h4" align="center" gutterBottom>Powerful Features</Typography>
        <Grid container spacing={4} sx={{ mt: 2 }}>
          {features.map((f, i) => (
            <Grid item xs={12} sm={6} md={3} key={i}>
              <Card sx={{ textAlign: 'center', p: 4 }}>
                <Box sx={{ bgcolor: alpha(f.color, 0.1), borderRadius: '50%', width: 80, height: 80, display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 20px' }}>
                  {React.cloneElement(f.icon, { sx: { fontSize: 40, color: f.color } })}
                </Box>
                <Typography variant="h6">{f.title}</Typography>
                <Typography color="text.secondary">{f.description}</Typography>
              </Card>
            </Grid>
          ))}
        </Grid>
      </Container>
      <Box sx={{ bgcolor: '#fff0f5', py: 8 }}>
        <Container maxWidth="md" sx={{ textAlign: 'center' }}>
          <Typography variant="h4" gutterBottom>Ready to Transform Your Resume?</Typography>
          <Button variant="contained" size="large" onClick={() => navigate('/signup')} sx={{ mt: 2, px: 6 }} startIcon={<AutoAwesomeIcon />}>Start Free Trial</Button>
        </Container>
      </Box>
    </Box>
  );
};

// ==================== LAYOUT ====================

const Layout = ({ children }) => {
  const [mobileOpen, setMobileOpen] = useState(false);
  const { user, logout } = React.useContext(AuthContext);
  const navigate = useNavigate();
  const drawerWidth = 260;

  const menuItems = [
    { text: 'Dashboard', icon: <DashboardIcon />, path: '/dashboard' },
    { text: 'Upload Resume', icon: <UploadIcon />, path: '/upload' },
    { text: 'ATS Analysis', icon: <AssessmentIcon />, path: '/analyze' },
    { text: 'Job Matcher', icon: <WorkIcon />, path: '/match' },
    { text: 'History', icon: <HistoryIcon />, path: '/history' },
  ];

  const drawer = (
    <div>
      <Toolbar><AnalyticsIcon sx={{ mr: 1, color: '#ff69b4' }} /><Typography variant="h6" sx={{ color: '#ff69b4' }}>Resume Analyzer</Typography></Toolbar>
      <Divider />
      <List>
        {menuItems.map((item) => (
          <ListItem button key={item.text} onClick={() => { navigate(item.path); setMobileOpen(false); }} sx={{ mx: 1, borderRadius: 2, mb: 0.5 }}>
            <ListItemIcon sx={{ color: '#ff69b4', minWidth: 40 }}>{item.icon}</ListItemIcon>
            <ListItemText primary={item.text} />
          </ListItem>
        ))}
      </List>
    </div>
  );

  return (
    <Box sx={{ display: 'flex' }}>
      <AppBar position="fixed" sx={{ zIndex: 1201, background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)' }}>
        <Toolbar>
          <IconButton color="inherit" edge="start" onClick={() => setMobileOpen(!mobileOpen)} sx={{ mr: 2, display: { md: 'none' } }}><MenuIcon /></IconButton>
          <AnalyticsIcon sx={{ mr: 1 }} />
          <Typography variant="h6" sx={{ flexGrow: 1, cursor: 'pointer' }} onClick={() => navigate('/')}>Resume Analyzer</Typography>
          <Chip avatar={<Avatar sx={{ bgcolor: 'white', color: '#ff69b4' }}>{user?.username?.[0]?.toUpperCase()}</Avatar>} label={user?.username} sx={{ color: 'white', borderColor: 'white' }} variant="outlined" />
          <IconButton color="inherit" onClick={logout}><LogoutIcon /></IconButton>
        </Toolbar>
      </AppBar>
      <Drawer variant="permanent" sx={{ display: { xs: 'none', md: 'block' }, width: drawerWidth, flexShrink: 0, '& .MuiDrawer-paper': { width: drawerWidth, mt: 8, borderRight: '1px solid #f0f0f0' } }} open>{drawer}</Drawer>
      <Drawer variant="temporary" open={mobileOpen} onClose={() => setMobileOpen(false)} sx={{ display: { xs: 'block', md: 'none' }, '& .MuiDrawer-paper': { width: drawerWidth } }}>{drawer}</Drawer>
      <Box component="main" sx={{ flexGrow: 1, p: 3, width: { xs: '100%', md: `calc(100% - ${drawerWidth}px)` }, mt: 8, backgroundColor: '#fff5f8', minHeight: '100vh' }}>{children}</Box>
    </Box>
  );
};

// ==================== DASHBOARD ====================

const DashboardPage = () => {
  const [resumes, setResumes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ total: 0, avgScore: 0 });
  const [viewMode, setViewMode] = useState('grid');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [resumesRes, historyRes] = await Promise.all([api.get('/resume/list'), api.get('/analysis/history')]);
      setResumes(resumesRes.data);
      const atsAnalyses = historyRes.data.filter(a => a.analysis_type === 'ats_score');
      const avgScore = atsAnalyses.reduce((s, a) => s + (a.ats_score || 0), 0) / (atsAnalyses.length || 1);
      setStats({ total: resumesRes.data.length, avgScore: Math.round(avgScore) });
    } catch (error) { console.error(error); } finally { setLoading(false); }
  };

  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh"><CircularProgress /></Box>;

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Welcome Back! 👋</Typography>
      <Grid container spacing={3} sx={{ mb: 4 }}>
        <Grid item xs={12} sm={6}>
          <Card sx={{ p: 3 }}>
            <Box display="flex" justifyContent="space-between"><Box><Typography color="text.secondary">Total Resumes</Typography><Typography variant="h3" fontWeight="bold">{stats.total}</Typography></Box><Box sx={{ bgcolor: alpha('#ff69b4', 0.1), borderRadius: 2, p: 1.5 }}><DescriptionIcon sx={{ fontSize: 40, color: '#ff69b4' }} /></Box></Box>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6}>
          <Card sx={{ p: 3 }}>
            <Box display="flex" justifyContent="space-between"><Box><Typography color="text.secondary">Avg ATS Score</Typography><Typography variant="h3" fontWeight="bold">{stats.avgScore}%</Typography></Box><Box sx={{ bgcolor: alpha('#51cf66', 0.1), borderRadius: 2, p: 1.5 }}><TrendingUpIcon sx={{ fontSize: 40, color: '#51cf66' }} /></Box></Box>
          </Card>
        </Grid>
      </Grid>
      <Box sx={{ mb: 4 }}>
        <Box display="flex" justifyContent="space-between" sx={{ mb: 3 }}><Typography variant="h5" fontWeight="bold">My Resumes</Typography><Button variant="contained" startIcon={<AddIcon />} component={Link} to="/upload">Upload</Button></Box>
        {resumes.length === 0 ? (
          <Card sx={{ textAlign: 'center', py: 8 }}><InsertDriveFileIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} /><Typography variant="h6">No Resumes Yet</Typography><Button variant="contained" component={Link} to="/upload" sx={{ mt: 2 }}>Upload Resume</Button></Card>
        ) : (
          <Grid container spacing={3}>
            {resumes.map((resume) => (
              <Grid item xs={12} sm={6} md={4} key={resume.id}>
                <Card><CardContent><Box display="flex" alignItems="center" gap={2}><Avatar sx={{ bgcolor: '#ff69b4' }}>{resume.name?.[0] || <DescriptionIcon />}</Avatar><Box><Typography variant="h6" noWrap>{resume.name || 'Unnamed'}</Typography><Typography variant="body2" color="text.secondary" noWrap>{resume.filename}</Typography></Box></Box><Box sx={{ mt: 2 }}><Typography variant="body2" color="text.secondary">Skills</Typography><Box display="flex" flexWrap="wrap" gap={0.5}>{resume.skills?.slice(0, 3).map(s => <Chip key={s} label={s} size="small" />)}</Box></Box></CardContent><Divider /><CardActions><Button size="small" startIcon={<AssessmentIcon />} component={Link} to={`/analyze?resume=${resume.id}`}>Analyze</Button><Button size="small" startIcon={<WorkIcon />} component={Link} to={`/match?resume=${resume.id}`}>Match</Button></CardActions></Card>
              </Grid>
            ))}
          </Grid>
        )}
      </Box>
    </Box>
  );
};

// ==================== UPLOAD ====================

const UploadPage = () => {
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });
  const navigate = useNavigate();

  const handleUpload = async () => {
    if (!file) { setMessage({ type: 'error', text: 'Select a file' }); return; }
    const formData = new FormData();
    formData.append('file', file);
    setUploading(true);
    try {
      await api.post('/resume/upload', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
      setMessage({ type: 'success', text: 'Uploaded! Redirecting...' });
      setTimeout(() => navigate('/dashboard'), 2000);
    } catch (error) {
      setMessage({ type: 'error', text: error.response?.data?.detail || 'Upload failed' });
    } finally {
      setUploading(false);
    }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Upload Resume</Typography>
      <Grid container spacing={4}>
        <Grid item xs={12} md={7}>
          <Card sx={{ p: 3 }}>
            <DropzoneArea acceptedFiles={['application/pdf', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document']} maxFileSize={10 * 1024 * 1024} filesLimit={1} onChange={(f) => setFile(f[0])} showAlerts={false} dropzoneText="Drag and drop or click to browse" />
            <Box sx={{ mt: 3, display: 'flex', justifyContent: 'center' }}>
              <Button variant="contained" onClick={handleUpload} disabled={!file || uploading} startIcon={<CloudUploadIcon />}>{uploading ? <CircularProgress size={24} /> : 'Upload'}</Button>
            </Box>
            {message.text && <Alert severity={message.type} sx={{ mt: 2 }}>{message.text}</Alert>}
          </Card>
        </Grid>
        <Grid item xs={12} md={5}>
          <Card sx={{ p: 3, bgcolor: '#fff0f5' }}>
            <Typography variant="h6">Supported Formats</Typography>
            <Box display="flex" gap={2} sx={{ mb: 2 }}><Chip icon={<PictureAsPdfIcon />} label="PDF" /><Chip icon={<ArticleIcon />} label="DOCX" /></Box>
            <Typography variant="body2" color="text.secondary">Max size: 10MB | Text-based PDF/DOCX</Typography>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

// ==================== ATS ANALYSIS ====================

const ATSAnalysisPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState(null);
  const [analysis, setAnalysis] = useState(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [tabValue, setTabValue] = useState(0);
  const location = useLocation();

  useEffect(() => {
    fetchResumes();
    const params = new URLSearchParams(location.search);
    const id = params.get('resume');
    if (id) setSelectedResume(parseInt(id));
  }, [location]);

  const fetchResumes = async () => {
    try {
      const res = await api.get('/resume/list');
      setResumes(res.data);
    } catch (error) { console.error(error); }
  };

  const handleAnalyze = async () => {
    if (!selectedResume) return;
    setAnalyzing(true);
    try {
      const res = await api.post('/analyze/ats', { resume_id: selectedResume });
      setAnalysis(res.data);
    } catch (error) { console.error(error); } finally { setAnalyzing(false); }
  };

  const getScoreColor = (score) => score >= 80 ? '#51cf66' : score >= 60 ? '#ff922b' : '#ff6b6b';

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">ATS Analysis</Typography>
      <Grid container spacing={4}>
        <Grid item xs={12} md={4}>
          <Card>
            <CardContent>
              <Typography variant="h6">Select Resume</Typography>
              <FormControl fullWidth sx={{ mt: 2 }}>
                <InputLabel>Choose a resume</InputLabel>
                <Select value={selectedResume || ''} onChange={(e) => setSelectedResume(e.target.value)} label="Choose a resume">
                  {resumes.map(r => <MenuItem key={r.id} value={r.id}>{r.name || r.filename}</MenuItem>)}
                </Select>
                {resumes.length === 0 && <FormHelperText>No resumes uploaded</FormHelperText>}
              </FormControl>
              <Button variant="contained" fullWidth onClick={handleAnalyze} disabled={!selectedResume || analyzing} sx={{ mt: 3 }} startIcon={<AutoAwesomeIcon />}>{analyzing ? <CircularProgress size={24} /> : 'Analyze'}</Button>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} md={8}>
          {analysis ? (
            <Fade in>
              <Box>
                <Card sx={{ mb: 3 }}>
                  <CardContent sx={{ textAlign: 'center' }}>
                    <Box sx={{ position: 'relative', display: 'inline-block', mb: 2 }}>
                      <CircularProgress variant="determinate" value={analysis.ats_score} size={120} thickness={4} sx={{ color: getScoreColor(analysis.ats_score) }} />
                      <Box sx={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)' }}><Typography variant="h3" fontWeight="bold">{Math.round(analysis.ats_score)}%</Typography></Box>
                    </Box>
                    <Typography variant="body2" color="text.secondary">ATS Score</Typography>
                    {analysis.score_breakdown && (
                      <Grid container spacing={2} sx={{ mt: 2 }}>
                        {Object.entries(analysis.score_breakdown).map(([k, v]) => (
                          <Grid item xs={6} sm={3} key={k}>
                            <Typography variant="caption" color="text.secondary">{k.replace(/_/g, ' ')}</Typography>
                            <Typography variant="h6">{Math.round(v)}%</Typography>
                            <LinearProgress variant="determinate" value={v} sx={{ height: 4, borderRadius: 2 }} />
                          </Grid>
                        ))}
                      </Grid>
                    )}
                  </CardContent>
                </Card>
                <Card>
                  <CardContent>
                    <Tabs value={tabValue} onChange={(e, v) => setTabValue(v)} variant="scrollable" scrollButtons="auto" sx={{ mb: 2 }}>
                      <Tab icon={<ThumbUpIcon />} label="Strengths" /><Tab icon={<ThumbDownIcon />} label="Weaknesses" />
                      <Tab icon={<SearchIcon />} label="Missing" /><Tab icon={<AutoAwesomeIcon />} label="Tips" />
                      <Tab icon={<PsychologyIcon />} label="Gaps" /><Tab icon={<TimelineIcon />} label="Plan" />
                    </Tabs>
                    {tabValue === 0 && <List>{analysis.strengths?.map((s, i) => <ListItem key={i}><CheckCircleIcon sx={{ color: 'success.main', mr: 2 }} />{s}</ListItem>)}</List>}
                    {tabValue === 1 && <List>{analysis.weaknesses?.map((w, i) => <ListItem key={i}><ErrorIcon sx={{ color: 'error.main', mr: 2 }} />{w}</ListItem>)}</List>}
                    {tabValue === 2 && <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>{analysis.missing_keywords?.map((k, i) => <Chip key={i} label={k} color="warning" />)}</Box>}
                    {tabValue === 3 && <List>{analysis.suggestions?.map((s, i) => <ListItem key={i}><LightbulbIcon sx={{ color: 'warning.main', mr: 2 }} />{s}</ListItem>)}</List>}
                    {tabValue === 4 && analysis.gap_analysis && (
                      <Box>
                        <Accordion><AccordionSummary expandIcon={<ExpandMoreIcon />}><Typography><SchoolIcon sx={{ mr: 1 }} />Skill Gaps</Typography></AccordionSummary><AccordionDetails><List>{analysis.gap_analysis.skill_gaps?.map((g, i) => <ListItem key={i}><TrendingDownIcon sx={{ mr: 1, color: 'error.main' }} />{g}</ListItem>)}</List></AccordionDetails></Accordion>
                        <Accordion><AccordionSummary expandIcon={<ExpandMoreIcon />}><Typography><WorkHistoryIcon sx={{ mr: 1 }} />Experience Gaps</Typography></AccordionSummary><AccordionDetails><List>{analysis.gap_analysis.experience_gaps?.map((g, i) => <ListItem key={i}><WarningIcon sx={{ mr: 1, color: 'warning.main' }} />{g}</ListItem>)}</List></AccordionDetails></Accordion>
                      </Box>
                    )}
                    {tabValue === 5 && analysis.improvement_plan && (
                      <Stepper orientation="vertical">
                        <Step active><StepLabel>Short-term (1-2 weeks)</StepLabel><StepContent><List>{analysis.improvement_plan.short_term?.map((i, idx) => <ListItem key={idx}><CheckIcon sx={{ color: 'success.main', mr: 1 }} />{i}</ListItem>)}</List></StepContent></Step>
                        <Step active><StepLabel>Medium-term (1-3 months)</StepLabel><StepContent><List>{analysis.improvement_plan.medium_term?.map((i, idx) => <ListItem key={idx}><TrendingUpIcon sx={{ color: 'warning.main', mr: 1 }} />{i}</ListItem>)}</List></StepContent></Step>
                        <Step active><StepLabel>Long-term (3-6 months)</StepLabel><StepContent><List>{analysis.improvement_plan.long_term?.map((i, idx) => <ListItem key={idx}><CelebrationIcon sx={{ color: 'primary.main', mr: 1 }} />{i}</ListItem>)}</List></StepContent></Step>
                      </Stepper>
                    )}
                  </CardContent>
                </Card>
              </Box>
            </Fade>
          ) : (
            <Card sx={{ textAlign: 'center', py: 8 }}><PsychologyIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} /><Typography variant="h6">Select a resume and click Analyze</Typography></Card>
          )}
        </Grid>
      </Grid>
    </Box>
  );
};

// ==================== JOB MATCHER ====================

const JobMatcherPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState(null);
  const [jobDescription, setJobDescription] = useState('');
  const [match, setMatch] = useState(null);
  const [matching, setMatching] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const location = useLocation();

  useEffect(() => {
    fetchResumes();
    const params = new URLSearchParams(location.search);
    const id = params.get('resume');
    if (id) setSelectedResume(parseInt(id));
  }, [location]);

  const fetchResumes = async () => {
    try {
      const res = await api.get('/resume/list');
      setResumes(res.data);
    } catch (error) { console.error(error); }
  };

  const handleMatch = async () => {
    if (!selectedResume || !jobDescription) return;
    setMatching(true);
    try {
      const res = await api.post('/analyze/match-job', { resume_id: selectedResume, job_description: jobDescription });
      setMatch(res.data);
      setOpenDialog(true);
    } catch (error) { console.error(error); } finally { setMatching(false); }
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Job Matcher</Typography>
      <Grid container spacing={4}>
        <Grid item xs={12} md={4}>
          <Card>
            <CardContent>
              <Typography variant="h6">Select Resume</Typography>
              <FormControl fullWidth sx={{ mt: 2 }}>
                <InputLabel>Choose a resume</InputLabel>
                <Select value={selectedResume || ''} onChange={(e) => setSelectedResume(e.target.value)} label="Choose a resume">
                  {resumes.map(r => <MenuItem key={r.id} value={r.id}>{r.name || r.filename}</MenuItem>)}
                </Select>
                {resumes.length === 0 && <FormHelperText>No resumes uploaded</FormHelperText>}
              </FormControl>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} md={8}>
          <Card>
            <CardContent>
              <Typography variant="h6">Job Description</Typography>
              <TextField fullWidth multiline rows={8} placeholder="Paste job description here..." value={jobDescription} onChange={(e) => setJobDescription(e.target.value)} sx={{ mb: 2 }} />
              <Button variant="contained" fullWidth onClick={handleMatch} disabled={!selectedResume || !jobDescription || matching} size="large" startIcon={<WorkIcon />}>{matching ? <CircularProgress size={24} /> : 'Match with Job'}</Button>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
      <Dialog open={openDialog} onClose={() => setOpenDialog(false)} maxWidth="md" fullWidth>
        <DialogTitle><Box display="flex" justifyContent="space-between"><Typography variant="h5">Match Results</Typography><Typography variant="h2" color="primary" fontWeight="bold">{Math.round(match?.match_percentage || 0)}%</Typography></Box></DialogTitle>
        <DialogContent dividers>
          <Typography variant="h6">Role Fit Summary</Typography>
          <Typography paragraph sx={{ bgcolor: '#fff0f5', p: 2, borderRadius: 2 }}>{match?.role_fit_summary}</Typography>
          <Typography variant="h6">✅ Matched Skills</Typography>
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1, mb: 2 }}>{match?.matched_skills?.map((s, i) => <Chip key={i} label={s} color="success" />)}</Box>
          <Typography variant="h6">💡 Improvement Tips</Typography>
          <List>{match?.improvement_tips?.map((t, i) => <ListItem key={i}><AutoAwesomeIcon sx={{ mr: 1, color: 'primary.main' }} />{t}</ListItem>)}</List>
        </DialogContent>
        <DialogActions><Button onClick={() => setOpenDialog(false)}>Close</Button></DialogActions>
      </Dialog>
    </Box>
  );
};

// ==================== HISTORY ====================

const HistoryPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => { fetchHistory(); }, []);

  const fetchHistory = async () => {
    try {
      const res = await api.get('/analysis/history');
      setHistory(res.data);
    } catch (error) { console.error(error); } finally { setLoading(false); }
  };

  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh"><CircularProgress /></Box>;

  return (
    <Box>
      <Typography variant="h4" gutterBottom fontWeight="bold">Analysis History</Typography>
      <Box sx={{ mb: 3 }}><ToggleButtonGroup value={filter} exclusive onChange={(e, v) => v && setFilter(v)}><ToggleButton value="all">All</ToggleButton><ToggleButton value="ats_score">ATS Scores</ToggleButton><ToggleButton value="job_match">Job Matches</ToggleButton></ToggleButtonGroup></Box>
      <Grid container spacing={2}>
        {history.filter(i => filter === 'all' || i.analysis_type === filter).map((item) => (
          <Grid item xs={12} key={item.id}>
            <Card><CardContent><Box display="flex" justifyContent="space-between"><Box><Typography variant="h6">{item.resume_name}</Typography><Typography variant="body2" color="text.secondary">{new Date(item.created_at).toLocaleString()}</Typography><Chip label={item.analysis_type === 'ats_score' ? 'ATS Score' : 'Job Match'} size="small" sx={{ mt: 1, bgcolor: '#ff69b4', color: 'white' }} /></Box><Typography variant="h3" color="primary" fontWeight="bold">{Math.round(item.analysis_type === 'ats_score' ? item.ats_score : item.match_percentage)}%</Typography></Box></CardContent></Card>
          </Grid>
        ))}
      </Grid>
      {history.length === 0 && <Paper sx={{ textAlign: 'center', py: 8 }}><HistoryIcon sx={{ fontSize: 80, color: 'text.secondary', mb: 2 }} /><Typography variant="h6">No History</Typography><Button variant="contained" component={Link} to="/upload" sx={{ mt: 2 }}>Upload Resume</Button></Paper>}
    </Box>
  );
};

// ==================== LOGIN ====================

const LoginPage = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await login(username, password);
      navigate('/dashboard');
    } catch (error) {
      setError('Invalid username or password');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)' }}>
      <Container maxWidth="sm"><Card sx={{ p: 4 }}><Box textAlign="center" mb={4}><Avatar sx={{ bgcolor: '#ff69b4', width: 64, height: 64, margin: '0 auto', mb: 2 }}><AnalyticsIcon sx={{ fontSize: 32 }} /></Avatar><Typography variant="h4" fontWeight="bold">Welcome Back</Typography></Box>
      <form onSubmit={handleSubmit}><TextField fullWidth label="Username" value={username} onChange={(e) => setUsername(e.target.value)} margin="normal" required /><TextField fullWidth label="Password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} margin="normal" required />
      {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}<Button type="submit" fullWidth variant="contained" size="large" disabled={loading} sx={{ mt: 3 }}>{loading ? <CircularProgress size={24} /> : 'Sign In'}</Button></form>
      <Box textAlign="center" mt={2}><Typography variant="body2">Don't have an account? <Link to="/signup" style={{ color: '#ff69b4' }}>Sign Up</Link></Typography></Box></Card></Container>
    </Box>
  );
};

// ==================== SIGNUP ====================

const SignupPage = () => {
  const [formData, setFormData] = useState({ username: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);
  const { signup } = React.useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await signup(formData);
      setSuccess(true);
      setTimeout(() => navigate('/login'), 2000);
    } catch (error) {
      setError(error.response?.data?.detail || 'Signup failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)' }}>
      <Container maxWidth="sm"><Card sx={{ p: 4 }}><Box textAlign="center" mb={4}><Avatar sx={{ bgcolor: '#ff69b4', width: 64, height: 64, margin: '0 auto', mb: 2 }}><AppRegistrationIcon sx={{ fontSize: 32 }} /></Avatar><Typography variant="h4" fontWeight="bold">Create Account</Typography></Box>
      <form onSubmit={handleSubmit}><TextField fullWidth label="Username" value={formData.username} onChange={(e) => setFormData({ ...formData, username: e.target.value })} margin="normal" required /><TextField fullWidth label="Email" type="email" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} margin="normal" required /><TextField fullWidth label="Password" type="password" value={formData.password} onChange={(e) => setFormData({ ...formData, password: e.target.value })} margin="normal" required />
      {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}{success && <Alert severity="success" sx={{ mt: 2 }}>Account created! Redirecting...</Alert>}<Button type="submit" fullWidth variant="contained" size="large" disabled={loading} sx={{ mt: 3 }}>{loading ? <CircularProgress size={24} /> : 'Sign Up'}</Button></form>
      <Box textAlign="center" mt={2}><Typography variant="body2">Already have an account? <Link to="/login" style={{ color: '#ff69b4' }}>Sign In</Link></Typography></Box></Card></Container>
    </Box>
  );
};

// ==================== MAIN APP ====================

const App = () => {
  const { user, loading } = React.useContext(AuthContext);
  if (loading) return <Box display="flex" justifyContent="center" alignItems="center" minHeight="100vh"><CircularProgress /></Box>;

  return (
    <Router>
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <LoginPage />} />
        <Route path="/signup" element={user ? <Navigate to="/dashboard" /> : <SignupPage />} />
        <Route path="/dashboard" element={user ? <Layout><DashboardPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/upload" element={user ? <Layout><UploadPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/analyze" element={user ? <Layout><ATSAnalysisPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/match" element={user ? <Layout><JobMatcherPage /></Layout> : <Navigate to="/login" />} />
        <Route path="/history" element={user ? <Layout><HistoryPage /></Layout> : <Navigate to="/login" />} />
      </Routes>
    </Router>
  );
};

const AppWrapper = () => (
  <ThemeProvider theme={theme}>
    <CssBaseline />
    <AuthProvider>
      <App />
    </AuthProvider>
  </ThemeProvider>
);

export default AppWrapper;
